-- TRILHA: CLOUD & DEVOPS AVANÇADO
SET @cloud_id = (SELECT id FROM courses WHERE title = 'Cloud & DevOps Avançado' LIMIT 1);

INSERT INTO modules (course_id, title) VALUES (@cloud_id, 'Fundamentos Cloud');
SET @cloud_mod1 = LAST_INSERT_ID();

INSERT INTO lessons (module_id, title, content) VALUES
(@cloud_mod1, 'Modelos de Cloud', '<h2>Modelos de Cloud</h2><h3>IaaS (Infrastructure as a Service)</h3><p>Você gerencia: aplicações, dados, runtime, middleware, SO</p><h3>PaaS (Platform as a Service)</h3><p>Você gerencia: aplicações, dados</p><h3>SaaS (Software as a Service)</h3><p>Você gerencia: nada (tudo é gerenciado pelo provedor)</p>'),
(@cloud_mod1, 'Provedores Cloud Principais', '<h2>Provedores Cloud</h2><h3>AWS (Amazon Web Services)</h3><p>Maior provedor, maior variedade de serviços</p><h3>Azure (Microsoft)</h3><p>Integração com ecossistema Microsoft</p><h3>GCP (Google Cloud Platform)</h3><p>Foco em dados e machine learning</p>'),
(@cloud_mod1, 'Vantagens e Desafios da Cloud', '<h2>Vantagens da Cloud</h2><ul><li>Escalabilidade automática</li><li>Pay-as-you-go</li><li>Disponibilidade global</li><li>Segurança gerenciada</li></ul><h2>Desafios</h2><ul><li>Custo pode ser imprevisível</li><li>Lock-in do provedor</li><li>Complexidade de gerenciamento</li></ul>');

INSERT INTO modules (course_id, title) VALUES (@cloud_id, 'Containerização');
SET @cloud_mod2 = LAST_INSERT_ID();

INSERT INTO lessons (module_id, title, content) VALUES
(@cloud_mod2, 'Docker Fundamentos', '<h2>Docker</h2><h3>Imagem</h3><p>Template para criar containers</p><h3>Container</h3><p>Instância em execução de uma imagem</p><h3>Dockerfile</h3><p>Arquivo que define como construir uma imagem</p>'),
(@cloud_mod2, 'Orquestração com Kubernetes', '<h2>Kubernetes</h2><h3>Pod</h3><p>Unidade mínima no Kubernetes</p><h3>Service</h3><p>Expõe pods para acesso externo</p><h3>Deployment</h3><p>Gerencia replicação de pods</p>'),
(@cloud_mod2, 'CI/CD Pipelines', '<h2>CI/CD</h2><h3>Continuous Integration</h3><p>Automatizar testes a cada commit</p><h3>Continuous Deployment</h3><p>Automatizar deploy em produção</p>');

INSERT INTO modules (course_id, title) VALUES (@cloud_id, 'Infraestrutura como Código');
SET @cloud_mod3 = LAST_INSERT_ID();

INSERT INTO lessons (module_id, title, content) VALUES
(@cloud_mod3, 'Terraform Fundamentos', '<h2>Terraform</h2><h3>HCL (HashiCorp Configuration Language)</h3><p>Linguagem declarativa para infraestrutura</p><h3>Providers</h3><p>Plugins para diferentes provedores (AWS, Azure, GCP)</p>'),
(@cloud_mod3, 'CloudFormation vs Terraform', '<h2>CloudFormation vs Terraform</h2><h3>CloudFormation</h3><p>Nativo da AWS, JSON/YAML</p><h3>Terraform</h3><p>Multi-cloud, HCL, mais flexível</p>'),
(@cloud_mod3, 'Monitoramento e Logging', '<h2>Monitoramento</h2><h3>CloudWatch</h3><p>Serviço de monitoramento da AWS</p><h3>Datadog</h3><p>Plataforma de observabilidade</p><h3>ELK Stack</h3><p>Elasticsearch, Logstash, Kibana</p>');

SELECT COUNT(*) as total_cloud FROM lessons WHERE module_id IN (SELECT id FROM modules WHERE course_id = @cloud_id);

